var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"…그래. 알겠네.","JPN":"……そうか。わかった。","ENG":"...All right. Understood.","TWN":"……嗯，知道了。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"됐습니다. 제 부하들이 길을 확보했으니 자리를 피하죠.","JPN":"準備はできました。私の部下が道を確保しているので、退きましょう。","ENG":"Done. My people have secured an escape route. We must leave now.","TWN":"可以了。我的部下已經確認撤退路線，我們先避一下吧。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L6_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"으윽…! 이 쇠사슬은 뭐야! 엄청 무거워!","JPN":"ううっ……！　この鎖何だよ！　めっちゃ重い！","ENG":"Ngh...! What's up with this chain?! It's so heavy!!","TWN":"呃呃……！這個鎖鏈是什麼鬼！好重！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"루나?!","JPN":"ルナさん！？","ENG":"Luna?!","TWN":"露娜？！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"하! 좋아, 한 녀석 잡았고!","JPN":"は！　よし、一人捕まえた！","ENG":"Hah! All right! That's one down!","TWN":"哈！很好，抓到了一個傢伙！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"이거 빨리 못 풀어, 볏짚 머리야?! 무슨 수상한 능력을 쓰는 거냐구!","JPN":"これ外しなさいよ、ワラ頭！！　怪しい能力使いやがって！","ENG":"Hey, get this off me, you punk! What kind of weird power are you using?!","TWN":"快點放開我，你這個稻草頭？！你用了什麼奇怪的能力！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"아니, 너 같은 꼬맹이한테 능력까지 쓰겠냐.","JPN":"いや、お前みたいなガキにまで能力は使わねえよ。","ENG":"Do you really think I'd use my powers on a kid like you?","TWN":"沒有，對付你這種小鬼，我還用得著動用能力嗎。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"거짓말! 무지 무겁다구!","JPN":"ウソつき！　だったらなんでこんなに重いんだよ！","ENG":"You’re lying! It's so heavy!","TWN":"騙人！真的好重啊！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그냥 평범한 쇠사슬인데…. 네가 너무 약해서 그런가 보다.","JPN":"ただの鎖なんだけどな……お前が弱すぎるんじゃねえ？","ENG":"It's just a normal chain... I guess you're just a lot weaker than you think.","TWN":"就是普通的鎖鏈……可能是因為你太弱了。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"이이이익…!","JPN":"こんのぉぉぉ……！","ENG":"Errrrgh...!","TWN":"嗚嗚嗚……！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"루나를 풀어 줘요!","JPN":"ルナさんを放してください！","ENG":"Let Luna go!","TWN":"放開露娜！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"맥크레디 양? 설마 그림자에게 연민이라도 느낀 겁니까?","JPN":"マクレディーさん？　まさかシャドウに同情でもしているのですか？","ENG":"Ms. MacCready? Are you feeling sympathy for a Shadow?","TWN":"麥克蕾蒂？你不會是可憐暗影吧？"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그림자든 아니든 본의 아니게 한 번은 목숨을 빚진 입장이에요.","JPN":"シャドウであれ何であれ、不本意ではありますが一度は命を助けられました。","ENG":"Shadow or not, she saved my life once.","TWN":"不管她是不是暗影，我之前都欠了她一條命。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"다른 데도 아니고 제 앞에서 죽는 꼴은 볼 수 없습니다!","JPN":"私の目の前で死なせるわけにはいきません！","ENG":"But more than that, I do not want to see her get killed in front of me!","TWN":"我不能眼睜睜看著她死在我面前！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"동료애 발휘할 상대를 잘못 골랐어, 귀족 나리!","JPN":"友情を発揮する相手を選び間違ったな、貴族のお嬢さん！","ENG":"You picked the wrong being to form a comradery with, missy!","TWN":"你選錯同情心氾濫的對象了，貴族小姐！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"윽!? 비겁하게 눈에 모래를……!","JPN":"うっ！？　卑怯ですわ、目に砂を……！","ENG":"Ngh?! Throwing sand? You coward...!","TWN":"呃！？太卑鄙了，沙子弄到我眼睛了……！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"맥크레디 양, 조심하게!","JPN":"マクレディー君、気をつけたまえ！","ENG":"Regina, look out!","TWN":"麥克蕾蒂，小心！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"크윽……!","JPN":"くうっ……！","ENG":"Kgh...!","TWN":"呃……！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"싸움에 비겁하고 말고가 어딨어? 너 손에 물은 묻혀 봤냐?","JPN":"戦いに卑怯もクソもあるか！　お前、手に水付けたこともないだろ？","ENG":"There's no such thing as cowardice in a fight. Don't you know anything?","TWN":"打架哪有什麼卑鄙不卑鄙的？你不會是個菜鳥吧？"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제가 세상 물정 모른다고 생각했다면 큰 오산입니다!","JPN":"私が世間知らずだと思ったら大間違いですわ！","ENG":"You are mistaken if you think that I am naive!","TWN":"如果你認為我無知，那就大錯特錯了！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"흠……? 방금 저 목소리는…….","JPN":"ふむ……？　今のあの声は……","ENG":"Hmm...? That voice...","TWN":"嗯……？剛才那聲音是……"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"학부장님, 도와 주세요! 이러다 부학회장님마저 잡혀 가시겠어요!","JPN":"学部長様、助けてください！　このままでは副学会長様まで捕まってしまいます！","ENG":"Sir, help her! Or she'll also get caught!","TWN":"學院院長，快幫幫忙啊！照這樣下去，副學會長該被抓走了！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"그래요. 걱정되신다면 가서 직접 맥크레디 양을 도와 주시죠.","JPN":"そうですね。心配なら自分で直接マクレディーさんを助けてやりなさい。","ENG":"All right. But if you are worrying about Ms. MacCready, you should help her yourself.","TWN":"是嗎，擔心的話你就自己去幫麥克蕾蒂吧。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"What...?","TWN":"什麼？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"하지만… 총알이 쌩쌩 날아다니는데, 제가 가도 부학회장님께 짐만 될 거예요.","JPN":"でも……銃弾が行き交ってるのに、私が行っても副学会長様の迷惑になるだけです。","ENG":"But... with all the bullets flying around... I'll only be a bother to her right now.","TWN":"可是……子彈在亂飛，就算我過去，也只會拖累副學會長。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"아쉽군요. 지금의 맥크레디 양에게는 저보다 당신이 더 힘이 되어 줄 텐데요.","JPN":"残念ですね。今のマクレディーさんには、私より君の方が力になるはずですが。","ENG":"Shame. Because right now, you will be of more help to her than I can.","TWN":"真可惜，對於現在的麥克蕾蒂來說，你比我更有用。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_B","text":{"KOREA":"교수님, 더 지체하다간 위험해질 수 있습니다.","JPN":"教授、これ以上ここにいては危険です。","ENG":"Professor, any further delays could put you in danger.","TWN":"教授，再拖下去可能會有危險。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_NPC_ESPR2_B","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"기다리게. 오래 전부터 존재했던 배후의 실체를 확인할 절호의 기회야.","JPN":"待て。昔から存在してきた裏の実体を確認する絶好のチャンスだ。","ENG":"Wait. I've been long waiting for this golden opportunity to find out who's been pulling the strings.","TWN":"再等等。這是確認很久以前就存在的幕後真相的絕佳機會。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_NPC_ESPR2_B","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_B","text":{"KOREA":"예? 배후라니요?","JPN":"え？　裏といいますと？","ENG":"What do you mean? \\"Pulling the strings\\"?","TWN":"什麼？幕後真相？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_NPC_ESPR2_B","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"방호복으로 동상을 막지 못할 수도 있다! 섣불리 접근하지 말고 엄호 사격으로 지원해!","JPN":"防護服で凍傷を防げないかもしれない！　迂闊に接近せず、援護射撃でサポートしろ！","ENG":"Your protective suits might not protect you from frostbite! Approach with caution and provide cover fire!","TWN":"防護服可能擋不住凍傷！不要貿然靠近，用掩護射擊支援！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하아…… 하아…… 이 양아치가…….","JPN":"はあ……はあ……この不良が……","ENG":"*Huff... Huff...* That jerk...","TWN":"呼呼……呼呼……你這個混蛋……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"누구더러 양아치래?","JPN":"誰が不良だよ。","ENG":"Who're you calling a jerk?","TWN":"你說誰是混蛋呢？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"네 부하들이 무슨 짓을 하고 다니나 자각은 있냐? 이제 아예 합중국을 뒤엎으려고 한다면서?","JPN":"部下が何をしてるか、お前はわかってるのか？　合衆国をひっくり返そうとしてるらしいぜ？","ENG":"Are you not aware of what your hooligans have been up to all this time? I heard you're now attempting to destabilise the States, no?","TWN":"你知道你的部下們究竟在幹什麼嗎？聽說現在要推翻合眾國？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저도 그 인간들 때문에 골치 아파 죽겠다고요!","JPN":"私もあの人たちのせいで困っているのです！","ENG":"I am always having headaches because of them!","TWN":"我也因為那些人頭痛得要死！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"사장님, 기관과 인연이 있다고 하지 않았어요?","JPN":"社長、機関とつながりがあるっておっしゃいませんでしたか？","ENG":"Boss, I believe you mentioned having ties to the Institution.","TWN":"老闆，你不是說你跟機關有淵源嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"뭐든지 해 드릴 테니까! 저 망나니 좀 어떻게 해 주세요!","JPN":"何でもしますから！　あのゴロツキ、何とかしてください！","ENG":"I will give you anything! Just do something about that prick!","TWN":"不管什麼我都會為你做！拜託你快點把這個混蛋搞定！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"부학회장에 학부장까지 동행하고 있는데 내가 말한다고 들어 주겠나?","JPN":"副学会長に学部長まで同行しているのに、私の話を聞いてくれると思うかね？","ENG":"I'm literally at your back, accompanied by a dean. Do you think they will even listen to what I say?","TWN":"副學會長還有學院院長都在呢，我說了他就會聽嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"도발에 휘둘리지 말게. 궁지에 몰려 있을 때일수록 냉정해져야 돼.","JPN":"挑発に振り回されるな。窮地に追い込まれた時こそ、冷静にならなければ。","ENG":"Don't let their taunts get to you. The more they corner you, the more you must keep your cool.","TWN":"不要被挑釁牽著鼻子走。越是陷入困境，越要保持冷靜。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……무슨 말이죠?","JPN":"……どういうことですの？","ENG":"What do you mean?","TWN":"……你什麼意思？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네 목표는 루나 양을 구출하는 것 아니었나?","JPN":"君の目標は、ルナ君を救出することだろう？","ENG":"Isn't your objective to rescue Luna?","TWN":"你的目標是救出露娜不是嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"버넷 군에게 집중하지 말게. 저 친구는 본능적으로 시선을 끌고 있는 거야.","JPN":"バーネット君を気にかけるな。あの者は本能的に目を引き付けようとしているんだ。","ENG":"Then stop focusing your attention on Burnett. All he's been doing is trying to distract you.","TWN":"別專注于伯內特。那個人就是在本能地吸引你的注意力。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"목표는 구출…….","JPN":"目標は救出……","ENG":"The goal is to rescue...","TWN":"目標是救出……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"고맙습니다. 확실히 휘둘리고 있었네요.","JPN":"ありがとうございます。確かに振り回されていましたわ。","ENG":"Thank you. You were right about him getting to me.","TWN":"謝謝你，我確實被他牽著鼻子走了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"웃……!? 아직 힘이 남아 있었나?","JPN":"うっ……！？　まだ力が残ってたのか？","ENG":"Hmm...?! How are you still able to get up?","TWN":"呃……！？還有力氣嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"대치 상태가 무너져선 안 돼! 어서 엄호해!","JPN":"対峙状態が崩れてはいけない！　早く援護しろ！","ENG":"Don't break formation! Cover them!","TWN":"僵持狀態不能崩潰！快點掩護！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"한 발 늦었습니다! 루나는 제가 데려가겠어요!","JPN":"もう遅いですわ！　ルナさんは返していただきます！","ENG":"Too slow! I will take Luna!","TWN":"你慢了一步！露娜我帶走了！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"고, 고마워! 부학회……","JPN":"あ、ありがとう！　副学会……","ENG":"Th-thanks, Vice Pre–","TWN":"謝…謝謝你！副會……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"자갹?! 왜 멀쩡한 머리채 잡고 끌고 가는 건데에!","JPN":"長ぉっ？！　なんで髪を掴んで引きずってくんだよ！","ENG":"Eeeek! Why are you grabbing me by my hair?!","TWN":"哎呀？！為什麼要抓著我的頭髮拖著我走！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"급하니까 이해해 주세요! 잠시라도 지체하다간 당한다고요!","JPN":"急いでますので、理解してください！　少しでも遅れればやられてしまいますわ！","ENG":"We are in a hurry. Please understand! We have to make every second count!","TWN":"事出緊急，請你理解一下！再繼續耽誤下去就走不掉了！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"으아앙! 이 바보 멍청이 부학회장! 저주해 버릴 거야!","JPN":"わあーん！　副学会長のばか！　呪ってやるんだから！","ENG":"Waaaah! Stupid Vice President! I'm going to curse you...!","TWN":"呃啊啊！你這個笨蛋傻瓜副學會長！我要詛咒你！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_HATE"},"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"으으……. 갈비뼈에 금이 갔나. 저런 맹한 아가씨에게 역으로 한 방 먹다니.","JPN":"うう……肋骨にヒビ入ったか？　あんなぼうっとしたお嬢さんに逆に一発食らうなんて。","ENG":"Ugh... I think I broke a rib... I can't believe I let my guard down like that.","TWN":"呃呃……肋骨裂了嗎。居然被那愚蠢的大小姐反過來給揍了一頓。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"요원님, 몸은 좀 어때? 방금 전 공격은 상당히 위험했던 것 같은데.","JPN":"身体は大丈夫か？　さっきの攻撃は相当危険そうだったが。","ENG":"Agent, are you okay? That last attack appeared to be quite dangerous.","TWN":"特務，身體怎麼樣？剛才的攻擊好像相當危險呢。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L32_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"읏차, 싸움에 완승이 어디 있어.","JPN":"よいしょっと、戦いに完勝なんかねえよ。","ENG":"Well, there's no such thing as a \\"landslide victory\\" in a fight.","TWN":"哼，打架哪有必勝的。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"한두 번 나가떨어진 것 정도로 징징거릴 수는 없지.","JPN":"1、2回倒れたくらいでめそめそ泣くわけにはいかないだろ。","ENG":"I can't complain about a few punches here and there.","TWN":"不能因為遇到挫折就抱怨不停。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그보다 저 인간들, 놓쳐도 되는 거야?","JPN":"それよりあいつら、逃してもいいのか？","ENG":"Besides that, aren't you going to chase after them?","TWN":"話說回來，那些人，放走也沒關係嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"좋아. 터프한 건 버넷 경 이상일지도 모르겠군.","JPN":"よし。タフさはバーネット卿以上かもしれないな。","ENG":"All right. Maybe you're tougher than Sir Burnett.","TWN":"很好。你看起來比伯內特卿還要強悍。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"상부에 전략 위성 사용을 요청해 뒀어. 포착될 동안 숨 좀 돌리고 있으라고.","JPN":"上層部に戦略衛星の使用を要請しておいた。捕捉するまで一息入れておけ。","ENG":"I requested authorization to use the strategic satellites. Catch your breath while we wait for it to track them.","TWN":"我已經向上級申請使用戰略衛星了。在衛星搜尋敵人期間，你先休息一下吧。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그런데 부학회장 어깨에 앉아 있던 까마귀는 뭐지……? 어디서 들어 본 목소리 같았는데?","JPN":"ところでさ、副学会長の肩に乗ってたカラスって何なんだ……？　どっかで聞いたことがあるような声だったぜ。","ENG":"But that crow that was sitting on the Vice President's shoulder... What was that? I'm certain I've heard that voice from somewhere before...","TWN":"不過坐在副學會長肩膀上的烏鴉是什麼……？總感覺在哪兒聽過那個聲音？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};